"use client";

import { FormEvent, useState } from "react";

export default function ContactForm() {
  const [submitted, setSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    const form = event.currentTarget;
    const formData = new FormData(form);

    const payload = {
      name: String(formData.get("name") ?? "").trim(),
      company: String(formData.get("company") ?? "").trim(),
      email: String(formData.get("email") ?? "").trim(),
      inquiryType: String(formData.get("inquiryType") ?? "").trim(),
      message: String(formData.get("message") ?? "").trim(),
    };

    if (!payload.name || !payload.company || !payload.email || !payload.message) {
      setError("Please complete all required fields.");
      setSubmitted(false);
      return;
    }

    setIsSubmitting(true);
    setError(null);
    setSubmitted(false);

    try {
      const response = await fetch("/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const result = (await response.json()) as { success?: boolean; error?: string };

      if (!response.ok || !result.success) {
        setError(result.error ?? "Unable to submit inquiry. Please try again.");
        return;
      }

      setSubmitted(true);
      form.reset();
    } catch {
      setError("Network error. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="card space-y-5">
      <div className="space-y-2 border-b border-slate-200 pb-4">
        <p className="text-sm font-semibold text-slate-900">Business Inquiry Form</p>
        <p className="text-sm text-slate-600">
          For partnership inquiries, please use your company email for faster
          processing.
        </p>
      </div>

      <div>
        <label htmlFor="name" className="mb-1 block text-sm font-medium text-slate-700">
          Full Name
        </label>
        <input
          id="name"
          name="name"
          required
          className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none transition focus:border-brand-600"
          placeholder="Your full name"
        />
      </div>

      <div>
        <label htmlFor="company" className="mb-1 block text-sm font-medium text-slate-700">
          Company Name
        </label>
        <input
          id="company"
          name="company"
          required
          className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none transition focus:border-brand-600"
          placeholder="Your company"
        />
      </div>

      <div>
        <label htmlFor="email" className="mb-1 block text-sm font-medium text-slate-700">
          Email
        </label>
        <input
          id="email"
          name="email"
          type="email"
          required
          className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none transition focus:border-brand-600"
          placeholder="name@company.com"
        />
      </div>

      <div>
        <label
          htmlFor="inquiryType"
          className="mb-1 block text-sm font-medium text-slate-700"
        >
          I am a (optional)
        </label>
        <select
          id="inquiryType"
          name="inquiryType"
          className="w-full rounded-lg border border-slate-300 bg-white px-3 py-2 text-sm outline-none transition focus:border-brand-600"
          defaultValue=""
        >
          <option value="">Select one</option>
          <option value="Brand">Brand</option>
          <option value="Distributor">Distributor</option>
          <option value="Other">Other</option>
        </select>
      </div>

      <div>
        <label htmlFor="message" className="mb-1 block text-sm font-medium text-slate-700">
          Message
        </label>
        <textarea
          id="message"
          name="message"
          rows={5}
          required
          className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none transition focus:border-brand-600"
          placeholder="Share your partnership objectives and business requirements."
        />
      </div>

      <button
        type="submit"
        disabled={isSubmitting}
        className="btn-primary"
      >
        {isSubmitting ? "Sending..." : "Submit Inquiry"}
      </button>

      {error ? (
        <p className="text-sm font-medium text-red-700">{error}</p>
      ) : null}

      {submitted ? (
        <p className="text-sm font-medium text-green-700">
          Thank you for contacting Purfavor. Our team will respond shortly.
        </p>
      ) : null}
    </form>
  );
}
